54	import { createClient, type SupabaseClient } from "npm:@supabase/supabase-js@2";
55	import { signJwt } from "../_shared/jwt.ts";
56	import { corsHeaders } from "../_shared/cors.ts";
57	import {
58	  type ApifyDispatchLink,
59	  dispatchApifyForLinks,
60	  type MetricsKey,
61	  type MetricsStatus,
62	} from "../_shared/apify-dispatch.ts";
63	
64	interface SignupRequest {
65	  username?: unknown;
66	  tiktok_handle?: unknown;
67	  instagram_handle?: unknown;
68	}
69	
70	function jsonResponse(status: number, body: unknown): Response {
71	  return new Response(JSON.stringify(body), {
72	    status,
73	    headers: { ...corsHeaders, "Content-Type": "application/json" },
74	  });
75	}
76	
77	function isString(value: unknown): value is string {
78	  return typeof value === "string";
79	}
80	
81	function normalizeHandle(value: unknown): string | null {
82	  if (!isString(value)) return null;
83	  const stripped = value.trim().replace(/^@+/, "").trim();
84	  return stripped.length > 0 ? stripped : null;
85	}
86	
87	Deno.serve(async (req) => {
88	  if (req.method === "OPTIONS") {
89	    return new Response(null, { status: 204, headers: corsHeaders });
90	  }
91	  if (req.method !== "POST") {
92	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
93	  }
94	
95	  let body: SignupRequest;
96	  try {
97	    body = await req.json();
98	  } catch {
99	    return jsonResponse(400, { error: "INVALID_JSON" });
100	  }
101	
102	  const username =
103	    isString(body.username) && body.username.trim().length > 0
104	      ? body.username.trim()
105	      : null;
106	  const tiktokHandle = normalizeHandle(body.tiktok_handle);
107	  const instagramHandle = normalizeHandle(body.instagram_handle);
108	
109	  if (!username) {
110	    return jsonResponse(400, { error: "INVALID_REQUEST" });
111	  }
112	  if (!tiktokHandle && !instagramHandle) {
113	    return jsonResponse(422, { error: "HANDLE_REQUIRED" });
114	  }
115	
116	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
117	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
118	  if (!supabaseUrl || !serviceRoleKey) {
119	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
120	  }
121	
122	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
123	    auth: { persistSession: false, autoRefreshToken: false },
124	  });
125	
126	  const { data, error } = await supabase.rpc("auth_signup_creator", {
127	    p_username: username,
128	    p_tiktok_handle: tiktokHandle,
129	    p_instagram_handle: instagramHandle,
130	  });
131	
132	  if (error) {
133	    console.error("auth_signup_creator rpc error", error);
134	    return jsonResponse(500, { error: "DB_ERROR" });
135	  }
136	
137	  const result = data as { user_id?: string; error?: string } | null;
138	  if (result?.error === "USERNAME_TAKEN") {
139	    return jsonResponse(409, { error: "USERNAME_TAKEN" });
140	  }
141	  if (result?.error === "HANDLE_TAKEN") {
142	    return jsonResponse(409, { error: "HANDLE_TAKEN" });
143	  }
144	  if (!result?.user_id) {
145	    console.error("auth_signup_creator returned unexpected shape", result);
146	    return jsonResponse(500, { error: "DB_ERROR" });
147	  }
148	
149	  const userId = result.user_id;
150	  const sessionId = crypto.randomUUID();
151	  let token: string;
152	  try {
153	    token = await signJwt({
154	      sub: userId,
155	      app_role: "creator",
156	      session_id: sessionId,
157	    });
158	  } catch (err) {
159	    console.error("signJwt failed", err);
160	    return jsonResponse(500, { error: "JWT_ERROR" });
161	  }
162	
163	  const metricsStatus = await dispatchApifyRuns({
164	    supabase,
165	    supabaseUrl,
166	    userId,
167	    tiktokHandle,
168	    instagramHandle,
169	  });
170	
171	  return jsonResponse(200, {
172	    token,
173	    user_id: userId,
174	    role: "creator",
175	    metrics_status: metricsStatus,
176	  });
177	});
