179	// Dispatches the Apify runs required for the freshly-created creator
180	// account. Returns a partial metrics_status map keyed by platform. If
181	// APIFY_KEY or APIFY_WEBHOOK_SECRET is unset (e.g. local dev without
182	// Apify credentials), logs a warning and returns {} — the account is
183	// still usable, the client just won't see any metrics until a future
184	// scrape picks it up. A failure to dispatch a single platform does not
185	// affect the others.
186	// deno-lint-ignore no-explicit-any -- supabase-js generic args differ between
187	// the createClient call above (inferred as public schema) and any helper
188	// import; typing this parameter loosely avoids a widening mismatch.
189	async function dispatchApifyRuns(params: {
190	  supabase: SupabaseClient<any, any, any>;
191	  supabaseUrl: string;
192	  userId: string;
193	  tiktokHandle: string | null;
194	  instagramHandle: string | null;
195	}): Promise<Partial<Record<MetricsKey, MetricsStatus>>> {
196	  const { supabase, supabaseUrl, userId } = params;
197	
198	  const apifyKey = Deno.env.get("APIFY_KEY");
199	  const webhookSecret = Deno.env.get("APIFY_WEBHOOK_SECRET");
200	  if (!apifyKey || !webhookSecret) {
201	    console.warn(
202	      "apify dispatch skipped: APIFY_KEY or APIFY_WEBHOOK_SECRET missing",
203	    );
204	    return {};
205	  }
206	
207	  const { data: links, error: linksError } = await supabase
208	    .from("social_links")
209	    .select("id,platform,handle")
210	    .eq("user_id", userId);
211	  if (linksError) {
212	    console.error("social_links lookup failed", linksError);
213	    return {};
214	  }
215	
216	  const linkRows = (links ?? []) as Array<
217	    { id: string; platform: string; handle: string }
218	  >;
219	  const dispatchLinks: ApifyDispatchLink[] = linkRows
220	    .filter((l) => l.platform === "tiktok" || l.platform === "instagram")
221	    .map((l) => ({
222	      linkId: l.id,
223	      platform: l.platform as "tiktok" | "instagram",
224	      handle: l.handle,
225	    }));
226	
227	  return await dispatchApifyForLinks({ supabaseUrl, links: dispatchLinks });
228	}
