1	// Shared helper: dispatches Apify runs for one or more social_links rows
2	// and returns a partial metrics_status map keyed by platform/scrape mode.
3	//
4	// Used by auth-signup-creator (US-020) and manage-social-link (US-035) so
5	// both flows kick the same Apify scrapes with identical webhook payloads.
6	//
7	// Env: APIFY_KEY + APIFY_WEBHOOK_SECRET. If either is missing (e.g. local
8	// dev without Apify credentials), logs a warning and returns {}.
9	
10	import {
11	  type ApifyRunResult,
12	  type ApifyWebhookSpec,
13	  runInstagramDetails,
14	  runInstagramPosts,
15	  runTikTokProfile,
16	} from "./apify.ts";
17	
18	const APIFY_WAIT_SECS = 60;
19	const APIFY_TERMINAL_EVENTS = [
20	  "ACTOR.RUN.SUCCEEDED",
21	  "ACTOR.RUN.FAILED",
22	  "ACTOR.RUN.TIMED_OUT",
23	  "ACTOR.RUN.ABORTED",
24	];
25	
26	export interface ApifyDispatchLink {
27	  linkId: string;
28	  platform: "tiktok" | "instagram";
29	  handle: string;
30	}
31	
32	export type MetricsKey = "tiktok" | "ig_details" | "ig_posts";
33	export type MetricsStatus = "fresh" | "refreshing" | "failed";
34	
35	export async function dispatchApifyForLinks(params: {
36	  supabaseUrl: string;
37	  links: ApifyDispatchLink[];
38	}): Promise<Partial<Record<MetricsKey, MetricsStatus>>> {
39	  const { supabaseUrl, links } = params;
40	  const metricsStatus: Partial<Record<MetricsKey, MetricsStatus>> = {};
41	
42	  const apifyKey = Deno.env.get("APIFY_KEY");
43	  const webhookSecret = Deno.env.get("APIFY_WEBHOOK_SECRET");
44	  if (!apifyKey || !webhookSecret) {
45	    console.warn(
46	      "apify dispatch skipped: APIFY_KEY or APIFY_WEBHOOK_SECRET missing",
47	    );
48	    return metricsStatus;
49	  }
50	
51	  const webhookUrl = `${supabaseUrl}/functions/v1/apify-webhook`;
52	  const buildWebhook = (
53	    linkId: string,
54	    scrapeMode: "tiktok_profile" | "ig_details" | "ig_posts",
55	  ): ApifyWebhookSpec => ({
56	    eventTypes: APIFY_TERMINAL_EVENTS,
57	    requestUrl: webhookUrl,
58	    payloadTemplate: JSON.stringify({
59	      eventType: "{{eventType}}",
60	      resource: {
61	        id: "{{resource.id}}",
62	        defaultDatasetId: "{{resource.defaultDatasetId}}",
63	        status: "{{resource.status}}",
64	        actId: "{{resource.actId}}",
65	      },
66	      social_link_id: linkId,
67	      scrape_mode: scrapeMode,
68	      run_id: "{{resource.id}}",
69	      dataset_id: "{{resource.defaultDatasetId}}",
70	    }),
71	    headersTemplate: JSON.stringify({
72	      "X-Apify-Webhook-Secret": webhookSecret,
73	    }),
74	    shouldInterpolateStrings: true,
75	  });
76	
77	  interface Task {
78	    key: MetricsKey;
79	    run: () => Promise<ApifyRunResult>;
80	  }
81	  const tasks: Task[] = [];
82	  for (const link of links) {
83	    if (link.platform === "tiktok") {
84	      tasks.push({
85	        key: "tiktok",
86	        run: () =>
87	          runTikTokProfile(link.handle, {
88	            waitSecs: APIFY_WAIT_SECS,
89	            webhooks: [buildWebhook(link.linkId, "tiktok_profile")],
90	          }),
91	      });
92	    } else if (link.platform === "instagram") {
93	      tasks.push({
94	        key: "ig_details",
95	        run: () =>
96	          runInstagramDetails(link.handle, {
97	            waitSecs: APIFY_WAIT_SECS,
98	            webhooks: [buildWebhook(link.linkId, "ig_details")],
99	          }),
100	      });
101	      tasks.push({
102	        key: "ig_posts",
103	        run: () =>
104	          runInstagramPosts(link.handle, {
105	            waitSecs: APIFY_WAIT_SECS,
106	            webhooks: [buildWebhook(link.linkId, "ig_posts")],
107	          }),
108	      });
109	    }
110	  }
111	
112	  if (tasks.length === 0) return metricsStatus;
113	
114	  const settled = await Promise.allSettled(tasks.map((t) => t.run()));
115	  settled.forEach((outcome, i) => {
116	    const key = tasks[i].key;
117	    if (outcome.status === "fulfilled") {
118	      const s = outcome.value.status;
119	      metricsStatus[key] = s === "SUCCEEDED"
120	        ? "fresh"
121	        : s === "READY" || s === "RUNNING" ||
122	            s === "TIMING-OUT" || s === "ABORTING"
123	        ? "refreshing"
124	        : "failed";
125	    } else {
126	      console.error(`apify ${key} dispatch failed`, outcome.reason);
127	      metricsStatus[key] = "failed";
128	    }
129	  });
130	
131	  return metricsStatus;
132	}
